return items.map((item) => {
  const message = item.json.message || item.json.message || {};
  const text = (message.text || "").toString().trim();
  const chatId = message.chat && message.chat.id ? message.chat.id : undefined;
  const lower = text.toLowerCase();
  return {
    json: {
      chatId,
      text,
      lowerText: lower
    }
  };
});

return items.map((item) => {
  const lowerText = (item.json.lowerText || "").toString();
  let intent = "unknown";
  let confidence = 0;
  let reason = "No matching keywords found.";
  const hasOnboarding = lowerText.includes("onboard") || lowerText.includes("onboarding") || lowerText.includes("new supplier");
  const hasRisk = lowerText.includes("risk") && lowerText.includes("supplier");
  if (hasOnboarding && !hasRisk) {
    intent = "supplier_onboarding";
    confidence = 0.95;
    reason = "Clear onboarding-related keywords detected.";
  } else if (hasRisk && !hasOnboarding) {
    intent = "supplier_risk";
    confidence = 0.95;
    reason = "Clear supplier risk-related keywords detected.";
  } else if (hasOnboarding && hasRisk) {
    intent = "unknown";
    confidence = 0.5;
    reason = "Both onboarding and risk keywords detected; ambiguous.";
  }
  return {
    json: {
      ...item.json,
      intent,
      confidence,
      intentReason: reason
    }
  };
});

function extractClientId(text) {
  const clientMatch = text.match(/client\s+([a-z0-9_-]+)/i);
  if (clientMatch && clientMatch[1]) {
    return clientMatch[1];
  }
  // Fallback client for demos
  return "demo-client";
}

function extractStatus(text) {
  const lower = text.toLowerCase();
  if (lower.includes("in progress")) return "IN_PROGRESS";
  if (lower.includes("awaiting approval") || lower.includes("pending approval")) return "AWAITING_APPROVAL";
  if (lower.includes("rejected")) return "REJECTED";
  return undefined;
}

return items.map((item) => {
  const text = (item.json.text || "").toString();
  const clientId = extractClientId(text);
  const status = extractStatus(text);
  const limitMatch = text.match(/limit\s+(\d{1,3})/i);
  const limit = limitMatch ? parseInt(limitMatch[1], 10) : 50;
  const demo = /demo/i.test(text) ? "true" : "false";
  return {
    json: {
      ...item.json,
      query: {
        clientId,
        status,
        limit,
        demo
      }
    }
  };
});

return items.map((item) => {
  const envelope = item.json;
  if (!envelope.success) {
    const message = `❌ Error calling onboarding endpoint: ${envelope.error && envelope.error.message ? envelope.error.message : 'Unknown error'}`;
    return { json: { ...item.json, isError: true, textMessage: message, htmlTable: "" } };
  }
  const rows = envelope.data || [];
  const meta = envelope.meta || {};
  const count = Array.isArray(rows) ? rows.length : 0;
  const maxPreview = 15;
  const previewRows = rows.slice(0, maxPreview);
  const summaryLines = [];
  summaryLines.push(`✅ I found ${count} onboarding suppliers for client ${meta.clientId || 'unknown'}.`);
  if (count > maxPreview) {
    summaryLines.push(`I will show you the first ${maxPreview} here and attach a PDF with the complete list so the chat stays readable.`);
  }
  previewRows.forEach((r) => {
    summaryLines.push(`• ${r.name} – status: ${r.status}, industry: ${r.industry}, step: ${r.onboardingStep}`);
  });
  const textMessage = summaryLines.join("\n");
  const needsPdf = count > maxPreview;
  const header = `<tr><th>Name</th><th>Status</th><th>Industry</th><th>Compliance</th><th>Step</th><th>Registration Date</th></tr>`;
  const body = rows
    .map((r) => {
      let bgColor = "#e8f5e9";
      if (r.status === "AWAITING_APPROVAL") bgColor = "#fff8e1";
      if (r.status === "REJECTED") bgColor = "#ffebee";
      return `<tr style=\"background:${bgColor};\"><td>${r.name}</td><td>${r.status}</td><td>${r.industry}</td><td>${r.complianceStatus}</td><td>${r.onboardingStep}</td><td>${r.registrationDate}</td></tr>`;
    })
    .join("\n");
  const htmlTable = `<html><head><meta charset=\"utf-8\"/><style>body{font-family:Arial,sans-serif;font-size:12px;color:#263238;background:#fafafa;margin:16px;}h2{color:#1565c0;}p{margin-bottom:8px;}table{border-collapse:collapse;width:100%;background:#ffffff;border-radius:4px;overflow:hidden;}th,td{border:1px solid #ccc;padding:4px 6px;text-align:left;font-size:11px;}th{background:#f5f5f5;}</style></head><body><h2>Supplier Onboarding – Client ${meta.clientId || 'unknown'}</h2><p>Total suppliers: ${count}</p><table>${header}${body}</table></body></html>`;
  return {
    json: {
      ...item.json,
      textMessage,
      htmlTable,
      needsPdf
    }
  };
});

